data class SearchUiState(
    val query: String = "",
    val loading: Boolean = false,
    val items: List<JobUi> = emptyList(),
    val error: String? = null
)

sealed interface SearchAction {
    data class QueryChanged(val value: String) : SearchAction
    data object Retry : SearchAction
}

class JobDetailViewModel(
    savedStateHandle: SavedStateHandle,
    private val repository: JobRepository
) : ViewModel() {
    private val id: String = checkNotNull(savedStateHandle["jobId"])

    val uiState: StateFlow<JobDetailUiState> =
        repository.observeJob(id)
            .map<Job, JobDetailUiState> { JobDetailUiState.Content(it.toUi()) }
            .catch { emit(JobDetailUiState.Error(it.toUserMessage())) }
            .stateIn(
                viewModelScope,
                SharingStarted.WhileSubscribed(5_000),
                JobDetailUiState.Loading
            )
}

@Composable
fun JobDetailRoute(
    viewModel: JobDetailViewModel = hiltViewModel(),
    onBack: () -> Unit
) {
    val state by viewModel.uiState.collectAsStateWithLifecycle()
    JobDetailScreen(
        state = state,
        onRetry = viewModel::retry,
        onBack = onBack
    )
}

@Composable
fun JobDetailScreen(
    state: JobDetailUiState,
    onRetry: () -> Unit,
    onBack: () -> Unit
) { /* render only */ }
